import React, { useState, useRef, useEffect } from "react";
import Sidebar from "../../../components/Admin/Sidebar";
import TopBar from "../../../components/Admin//TopBar";
import { Link } from "react-router-dom";
import {
    TrendingUp, Building2, Users, DollarSign,
    Calendar, Filter, X, ChevronDown,
} from "lucide-react";
import { FaEllipsisV, FaEye, FaTrashAlt } from "react-icons/fa";

/* ─── Styles ─────────────────────────────────────────────────── */
const css = `
  /* Cards */
  .ar-card { background:#fff; border-radius:12px; border:1px solid #e8edf2; box-shadow:0 1px 3px rgba(0,0,0,.04); overflow:hidden; }
  .ar-card-hd { padding:14px 18px; border-bottom:1px solid #f1f5f9; font-weight:600; font-size:13px; color:#0f172a; display:flex; align-items:center; gap:8px; }
  .ar-card-hd svg { color:#ef4444; }

  /* Stat */
  .ar-stat { background:#fff; border-radius:10px; border:1px solid #e8edf2; box-shadow:0 1px 3px rgba(0,0,0,.04); padding:16px 14px; display:flex; align-items:center; gap:14px; }
  .ar-stat-icon { width:40px; height:40px; border-radius:10px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .ar-stat-val { font-size:20px; font-weight:700; color:#0f172a; line-height:1; }
  .ar-stat-lbl { font-size:11px; color:#94a3b8; margin-top:3px; }

  /* Filter bar */
  .ar-filter-bar { background:#fff; border:1px solid #e8edf2; border-radius:12px; padding:14px 18px; margin-bottom:20px; display:flex; flex-wrap:wrap; gap:12px; align-items:center; }
  .ar-search { position:relative; flex:1; min-width:200px; }
  .ar-search input { width:100%; padding:9px 14px 9px 38px; border:1.5px solid #e2e8f0; border-radius:10px; font-size:13px; color:#334155; background:#f8fafc; outline:none; font-family:inherit; transition:border-color .2s,box-shadow .2s; }
  .ar-search input:focus { border-color:#ef4444; box-shadow:0 0 0 3px rgba(239,68,68,.1); background:#fff; }
  .ar-search-icon { position:absolute; left:12px; top:50%; transform:translateY(-50%); color:#94a3b8; }
  .ar-select { padding:9px 32px 9px 12px; border:1.5px solid #e2e8f0; border-radius:10px; font-size:13px; color:#334155; background:#f8fafc; outline:none; font-family:inherit; cursor:pointer; appearance:none; min-width:160px; transition:border-color .2s; }
  .ar-select:focus { border-color:#ef4444; }
  .ar-select-wrap { position:relative; }
  .ar-select-wrap svg { position:absolute; right:10px; top:50%; transform:translateY(-50%); pointer-events:none; color:#94a3b8; }
  .ar-clear-btn { display:inline-flex; align-items:center; gap:6px; padding:9px 14px; border:1.5px solid #fecaca; background:#fff5f5; color:#ef4444; border-radius:10px; font-size:12px; font-weight:600; cursor:pointer; font-family:inherit; transition:background .15s; }
  .ar-clear-btn:hover { background:#fee2e2; }

  /* Table */
  .ar-table-wrap { width:100%; overflow-x:auto; -webkit-overflow-scrolling:touch; }
  .ar-table { width:100%; border-collapse:collapse; font-size:13px; min-width:900px; }
  .ar-table th { background:#f8fafc; padding:11px 16px; text-align:left; font-size:10px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:.05em; border-bottom:1px solid #e8edf2; white-space:nowrap; }
  .ar-table td { padding:13px 16px; border-bottom:1px solid #f8fafc; color:#334155; vertical-align:middle; }
  .ar-table tr:last-child td { border-bottom:none; }
  .ar-table tr:hover td { background:#fafafa; }

  /* Pills */
  .pill { display:inline-flex; align-items:center; gap:5px; border-radius:20px; padding:3px 10px; font-size:11px; font-weight:600; white-space:nowrap; }
  .pill::before { content:''; width:5px; height:5px; border-radius:50%; background:currentColor; flex-shrink:0; }
  .pill-green  { background:#dcfce7; color:#15803d; }
  .pill-gray   { background:#f1f5f9; color:#475569; }
  .pill-amber  { background:#fef3c7; color:#92400e; }
  .pill-blue   { background:#dbeafe; color:#1d4ed8; }
  .pill-purple { background:#ede9fe; color:#6d28d9; }
  .pill-red    { background:#fee2e2; color:#b91c1c; }

  /* Progress bar */
  .ar-progress-track { height:5px; background:#f1f5f9; border-radius:4px; width:80px; }
  .ar-progress-fill  { height:100%; border-radius:4px; background:#ef4444; transition:width .3s; }

  /* Company avatar */
  .ar-co-avatar { width:30px; height:30px; border-radius:7px; background:#fff5f5; color:#ef4444; display:flex; align-items:center; justify-content:center; font-weight:700; font-size:11px; flex-shrink:0; }

  /* Action dropdown */
  .au-action-btn { width:32px; height:32px; border:1.5px solid #e2e8f0; background:#fff; border-radius:8px; display:grid; place-items:center; cursor:pointer; color:#64748b; transition:background .15s,border-color .15s; padding:0; }
  .au-action-btn:hover { background:#f1f5f9; border-color:#cbd5e1; color:#0f172a; }
  .au-dropdown { position:fixed; min-width:175px; background:#fff; border:1px solid #e8edf2; border-radius:12px; box-shadow:0 8px 30px rgba(0,0,0,.13); padding:6px; z-index:99999; animation:auFadeIn .15s ease-out; }
  @keyframes auFadeIn { from{opacity:0;transform:translateY(-6px) scale(.97)} to{opacity:1;transform:translateY(0) scale(1)} }
  .au-drop-item { display:flex; align-items:center; gap:10px; padding:9px 12px; border-radius:8px; font-size:.84rem; font-weight:500; color:#334155; cursor:pointer; text-decoration:none !important; border:none; background:transparent; width:100%; font-family:inherit; transition:background .12s; line-height:1; }
  .au-drop-item:hover { background:#f1f5f9; color:#0f172a; }
  .au-drop-item.danger { color:#dc2626; }
  .au-drop-item.danger:hover { background:#fef2f2; }
  .au-drop-divider { height:1px; background:#f1f5f9; margin:5px 6px; }

  /* Empty state */
  .ar-empty { padding:60px 24px; text-align:center; color:#94a3b8; }
  .ar-empty-icon { font-size:2.5rem; margin-bottom:12px; opacity:.3; }

  /* Mobile scroll */
  @media(max-width:768px) { .ar-filter-bar { flex-direction:column; align-items:stretch; } .ar-search { min-width:100%; } }
`;

/* ─── Static Data ─────────────────────────────────────────────── */
const STATIC_ROUNDS = [
    { id: 1, company: "Neuo r", round: "Pre-Seed", type: "Equity", target: 200000, raised: 180000, investors: 3, status: "Closed", date: "Dec 2024", lead: "Avinay Kumar" },
    { id: 2, company: "Neuo r", round: "Seed", type: "Equity", target: 500000, raised: 280000, investors: 4, status: "Active", date: "Apr 2025", lead: "Rahul Sharma" },
    { id: 3, company: "TechVault Inc", round: "Seed", type: "Convertible", target: 300000, raised: 300000, investors: 5, status: "Closed", date: "Mar 2025", lead: "James Wilson" },
    { id: 4, company: "TechVault Inc", round: "Series A", type: "Equity", target: 1500000, raised: 600000, investors: 7, status: "Active", date: "Apr 2025", lead: "Priya Mehta" },
    { id: 5, company: "GreenGrow", round: "Pre-Seed", type: "Equity", target: 100000, raised: 100000, investors: 2, status: "Closed", date: "Jan 2025", lead: "Sara Johnson" },
    { id: 6, company: "GreenGrow", round: "Seed", type: "SAFE", target: 250000, raised: 80000, investors: 2, status: "Active", date: "Apr 2025", lead: "Sara Johnson" },
    { id: 7, company: "FinFlow", round: "Bridge", type: "Convertible", target: 150000, raised: 150000, investors: 3, status: "Closed", date: "Feb 2025", lead: "Mike Chen" },
    { id: 8, company: "FinFlow", round: "Series A", type: "Equity", target: 2000000, raised: 0, investors: 0, status: "Draft", date: "May 2025", lead: "—" },
    { id: 9, company: "HealthSync", round: "Pre-Seed", type: "Equity", target: 80000, raised: 80000, investors: 2, status: "Closed", date: "Nov 2024", lead: "Anita Roy" },
    { id: 10, company: "HealthSync", round: "Seed", type: "Equity", target: 400000, raised: 160000, investors: 3, status: "Active", date: "Mar 2025", lead: "Anita Roy" },
    { id: 11, company: "CloudBase AI", round: "Pre-Seed", type: "SAFE", target: 120000, raised: 120000, investors: 4, status: "Closed", date: "Oct 2024", lead: "Tom Bradley" },
    { id: 12, company: "CloudBase AI", round: "Seed", type: "Equity", target: 600000, raised: 350000, investors: 6, status: "Active", date: "Apr 2025", lead: "Tom Bradley" },
];

const COMPANIES = [...new Set(STATIC_ROUNDS.map(r => r.company))];
const STATUSES = ["Active", "Closed"];
const TYPES = [...new Set(STATIC_ROUNDS.map(r => r.type))];

const fmtMoney = (n) => n >= 1000000 ? `$${(n / 1000000).toFixed(1)}M` : n >= 1000 ? `$${(n / 1000).toFixed(0)}K` : `$${n}`;
const statusPill = { Open: "pill-green", Closed: "pill-gray", Draft: "pill-amber" };
const typePill = { Equity: "pill-blue", Convertible: "pill-purple", SAFE: "pill-red" };

/* ─── Action Dropdown ─────────────────────────────────────────── */
function ActionDropdown({ triggerRect, onClose }) {
    const ref = useRef(null);
    useEffect(() => {
        const h = (e) => { if (ref.current && !ref.current.contains(e.target)) onClose(); };
        document.addEventListener("mousedown", h);
        return () => document.removeEventListener("mousedown", h);
    }, [onClose]);
    const top = triggerRect ? triggerRect.bottom + window.scrollY + 4 : 0;
    const right = triggerRect ? window.innerWidth - triggerRect.right - window.scrollX : 0;
    return (
        <div ref={ref} className="au-dropdown" style={{ top, right: Math.max(right, 8) }}>
            <Link className="au-drop-item" to="/admin/company-round-detail"><FaEye size={12} /> View Details</Link>
            <div className="au-drop-divider" />
            <button className="au-drop-item danger"><FaTrashAlt size={12} /> Delete Round</button>
        </div>
    );
}

/* ─── Main ────────────────────────────────────────────────────── */
export default function AdminCompanyRound() {
    const [search, setSearch] = useState("");
    const [filterCo, setFilterCo] = useState("");
    const [filterSt, setFilterSt] = useState("");
    const [filterType, setFilterType] = useState("");
    const [openDrop, setOpenDrop] = useState(null);
    const [triggerRect, setTriggerRect] = useState(null);

    document.title = "Rounds - Admin";

    /* Filter logic */
    const filtered = STATIC_ROUNDS.filter(r => {
        const s = search.toLowerCase();
        const matchSearch = !s ||
            r.company.toLowerCase().includes(s) ||
            r.round.toLowerCase().includes(s) ||
            r.type.toLowerCase().includes(s) ||
            r.lead.toLowerCase().includes(s) ||
            r.status.toLowerCase().includes(s);
        const matchCo = !filterCo || r.company === filterCo;
        const matchSt = !filterSt || r.status === filterSt;
        const matchType = !filterType || r.type === filterType;
        return matchSearch && matchCo && matchSt && matchType;
    });

    const hasFilter = search || filterCo || filterSt || filterType;
    const clearAll = () => { setSearch(""); setFilterCo(""); setFilterSt(""); setFilterType(""); };

    /* Summary stats */
    const totalRaised = STATIC_ROUNDS.reduce((s, r) => s + r.raised, 0);
    const totalInvestors = STATIC_ROUNDS.reduce((s, r) => s + r.investors, 0);
    const openRounds = STATIC_ROUNDS.filter(r => r.status === "Open").length;

    const toggleDrop = (key, rect) => {
        if (openDrop === key) { setOpenDrop(null); }
        else { setOpenDrop(key); setTriggerRect(rect); }
    };

    const stats = [
        { label: "Total Rounds", value: STATIC_ROUNDS.length, icon: <TrendingUp size={16} />, color: "#ef4444", bg: "#fff5f5" },
        { label: "Open Rounds", value: openRounds, icon: <Calendar size={16} />, color: "#22c55e", bg: "#f0fdf4" },
        { label: "Total Raised", value: fmtMoney(totalRaised), icon: <DollarSign size={16} />, color: "#6366f1", bg: "#f5f3ff" },
        { label: "Total Investors", value: totalInvestors, icon: <Users size={16} />, color: "#f59e0b", bg: "#fffbeb" },
        { label: "Companies", value: COMPANIES.length, icon: <Building2 size={16} />, color: "#0ea5e9", bg: "#f0f9ff" },
    ];

    return (
        <>
            <style>{css}</style>
            <div>
                <div className="d-flex align-items-start gap-0">
                    <Sidebar />
                    <div className="d-flex flex-column gap-0 w-100 dashboard_padding">
                        <TopBar />
                        <section className="dashboard_adminh">
                            <div className="container-xl">
                                <div className="row gy-4">
                                    <div className="col-12">

                                        {/* Page Title */}
                                        <div className="d-flex align-items-center justify-content-between flex-wrap gap-2 mb-4">
                                            <div>
                                                <h5 className="mb-1 fw-semibold">Funding Rounds</h5>
                                                <p className="text-muted mb-0" style={{ fontSize: 13 }}>All rounds across all companies</p>
                                            </div>
                                        </div>

                                        {/* Stat Strip */}
                                        <div className="row g-3 mb-4">
                                            {stats.map((s, i) => (
                                                <div key={i} className="col-6 col-md">
                                                    <div className="ar-stat">
                                                        <div className="ar-stat-icon" style={{ background: s.bg, color: s.color }}>{s.icon}</div>
                                                        <div>
                                                            <div className="ar-stat-val">{s.value}</div>
                                                            <div className="ar-stat-lbl">{s.label}</div>
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>

                                        {/* Filter Bar */}
                                        <div className="ar-filter-bar">
                                            {/* Search */}
                                            <div className="ar-search">
                                                <span className="ar-search-icon">
                                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                                                        <circle cx="11" cy="11" r="8" /><path d="m21 21-4.35-4.35" />
                                                    </svg>
                                                </span>
                                                <input
                                                    type="text"
                                                    placeholder="Search rounds, company, type..."
                                                    value={search}
                                                    onChange={e => setSearch(e.target.value)}
                                                />
                                            </div>

                                            {/* Company Filter */}
                                            <div className="ar-select-wrap">
                                                <select className="ar-select" value={filterCo} onChange={e => setFilterCo(e.target.value)}>
                                                    <option value="">All Companies</option>
                                                    {COMPANIES.map(c => <option key={c} value={c}>{c}</option>)}
                                                </select>
                                                <ChevronDown size={13} />
                                            </div>

                                            {/* Status Filter */}
                                            <div className="ar-select-wrap">
                                                <select className="ar-select" value={filterSt} onChange={e => setFilterSt(e.target.value)}>
                                                    <option value="">All Statuses</option>
                                                    {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                                                </select>
                                                <ChevronDown size={13} />
                                            </div>

                                            {/* Type Filter */}
                                            <div className="ar-select-wrap">
                                                <select className="ar-select" value={filterType} onChange={e => setFilterType(e.target.value)}>
                                                    <option value="">All Types</option>
                                                    {TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                                </select>
                                                <ChevronDown size={13} />
                                            </div>

                                            {/* Clear */}
                                            {hasFilter && (
                                                <button className="ar-clear-btn" onClick={clearAll}>
                                                    <X size={12} /> Clear
                                                </button>
                                            )}

                                            {/* Result count */}
                                            <span style={{ fontSize: 12, color: "#94a3b8", marginLeft: "auto", whiteSpace: "nowrap" }}>
                                                {filtered.length} of {STATIC_ROUNDS.length} rounds
                                            </span>
                                        </div>

                                        {/* Table */}
                                        <div className="ar-card">
                                            <div className="ar-card-hd">
                                                <TrendingUp size={14} /> All Rounds
                                                <span style={{ background: "#f1f5f9", color: "#64748b", borderRadius: 20, padding: "1px 8px", fontSize: 11, fontWeight: 700, marginLeft: 4 }}>
                                                    {filtered.length}
                                                </span>
                                            </div>
                                            <div className="ar-table-wrap">
                                                {filtered.length === 0 ? (
                                                    <div className="ar-empty">
                                                        <div className="ar-empty-icon">📊</div>
                                                        <p className="mb-0 fw-500">No rounds found</p>
                                                        <p className="small text-muted mt-1">Try adjusting your filters</p>
                                                    </div>
                                                ) : (
                                                    <table className="ar-table">
                                                        <thead>
                                                            <tr>
                                                                <th>#</th>
                                                                <th>Company</th>
                                                                <th>Round</th>
                                                                <th>Type</th>
                                                                <th>Target</th>
                                                                <th>Raised</th>
                                                                <th>Progress</th>
                                                                <th>Investors</th>
                                                                <th>Lead Investor</th>
                                                                <th>Date</th>
                                                                <th>Status</th>
                                                                <th>Actions</th>
                                                            </tr>
                                                        </thead>
                                                        <tbody>
                                                            {filtered.map((r, i) => {
                                                                const pct = r.target > 0 ? Math.min(Math.round((r.raised / r.target) * 100), 100) : 0;
                                                                const barColor = pct === 100 ? "#22c55e" : pct > 50 ? "#f59e0b" : "#ef4444";
                                                                return (
                                                                    <tr key={r.id}>
                                                                        <td style={{ color: "#94a3b8", fontSize: 12 }}>{i + 1}</td>
                                                                        <td>
                                                                            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                                                                                <div className="ar-co-avatar">{r.company.charAt(0)}</div>
                                                                                <span style={{ fontWeight: 600 }}>{r.company}</span>
                                                                            </div>
                                                                        </td>
                                                                        <td style={{ fontWeight: 600, color: "#0f172a" }}>{r.round}</td>
                                                                        <td><span className={`pill ${typePill[r.type] || "pill-gray"}`}>{r.type}</span></td>
                                                                        <td style={{ fontFamily: "monospace", fontSize: 12 }}>{fmtMoney(r.target)}</td>
                                                                        <td style={{ fontWeight: 700, color: "#0f172a", fontFamily: "monospace", fontSize: 12 }}>{r.raised > 0 ? fmtMoney(r.raised) : "—"}</td>
                                                                        <td>
                                                                            {r.raised > 0 ? (
                                                                                <>
                                                                                    <div className="ar-progress-track">
                                                                                        <div className="ar-progress-fill" style={{ width: `${pct}%`, background: barColor }} />
                                                                                    </div>
                                                                                    <div style={{ fontSize: 10, color: "#94a3b8", marginTop: 3 }}>{pct}% funded</div>
                                                                                </>
                                                                            ) : <span style={{ color: "#cbd5e1", fontSize: 12 }}>Not started</span>}
                                                                        </td>
                                                                        <td style={{ textAlign: "center", fontWeight: 600 }}>{r.investors || "—"}</td>
                                                                        <td style={{ color: "#64748b", fontSize: 12 }}>{r.lead}</td>
                                                                        <td style={{ color: "#64748b", fontSize: 12, whiteSpace: "nowrap" }}>{r.date}</td>
                                                                        <td><span className={`pill ${statusPill[r.status] || "pill-gray"}`}>{r.status}</span></td>
                                                                        <td>
                                                                            <div style={{ position: "relative" }}>
                                                                                <button className="au-action-btn" onClick={(e) => { e.stopPropagation(); toggleDrop(r.id, e.currentTarget.getBoundingClientRect()); }}>
                                                                                    <FaEllipsisV size={11} />
                                                                                </button>
                                                                                {openDrop === r.id && (
                                                                                    <ActionDropdown triggerRect={triggerRect} onClose={() => setOpenDrop(null)} />
                                                                                )}
                                                                            </div>
                                                                        </td>
                                                                    </tr>
                                                                );
                                                            })}
                                                        </tbody>
                                                    </table>
                                                )}
                                            </div>
                                        </div>

                                    </div>
                                </div>
                            </div>
                        </section>
                    </div>
                </div>
            </div>
        </>
    );
}